ALGORITHM Interrupt_Driven_IO
INPUT: Device request from peripheral
OUTPUT: Data transfer between device and memory

// Global state
DECLARE interrupt_enabled = TRUE
DECLARE current_process_state
DECLARE interrupt_service_routine_addresses[256]

// Main CPU Execution Loop
BEGIN
 WHILE system_running DO
 // CPU executes main program
 EXECUTE main_program

 // Check for interrupt signal
 IF interrupt_line_active AND interrupt_enabled THEN
 // Step 1: Save CPU state
 current_process_state = SAVE_CPU_REGISTERS()

 // Step 2: Identify interrupt source
 interrupt_vector = READ_INTERRUPT_VECTOR()

 // Step 3: Disable further interrupts
 interrupt_enabled = FALSE

 // Step 4: Jump to ISR
 ISR_address = interrupt_service_routine_addresses[interrupt_vector]
 CALL ISR(ISR_address)

 // Step 5: Restore CPU state
 RESTORE_CPU_REGISTERS(current_process_state)

 // Step 6: Re-enable interrupts
 interrupt_enabled = TRUE
 END IF
 END WHILE
END

// Interrupt Service Routine
SUBROUTINE Handle_Device_Interrupt(device_id)
 BEGIN
 // Acknowledge the interrupt
 SEND_ACKNOWLEDGE(device_id)

 // Check device status
 status = READ_DEVICE_STATUS(device_id)

 IF status == DATA_READY THEN
 // Read data from device
 data = READ_DEVICE_DATA(device_id)

 // Process or store data
 STORE_TO_BUFFER(data)

 // Signal device that data was received
 SEND_COMPLETION(device_id)
 END IF

 RETURN
 END SUBROUTINE

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Interrupt priority levels (0 = highest priority)
#define PRIORITY_POWER_FAILURE 0
#define PRIORITY_TIMER 1
#define PRIORITY_KEYBOARD 2
#define PRIORITY_PRINTER 3
#define PRIORITY_DISK 4

// Maximum devices in daisy chain
#define MAX_DEVICES 5

// Interrupt request register bits
typedef struct {
 unsigned int power_fail : 1;
 unsigned int timer : 1;
 unsigned int keyboard : 1;
 unsigned int printer : 1;
 unsigned int disk : 1;
 unsigned int reserved : 3;
} InterruptRequestReg;

// Device structure for daisy chain
typedef struct {
 int device_id;
 int priority;
 char name[20];
 bool interrupt_enabled;
 void (*handler)(void);
 struct Device* next_device; // Daisy chain link
} Device;

// Global interrupt state
volatile InterruptRequestReg irq_register = {0, 0, 0, 0, 0, 0};
volatile bool global_interrupt_enable = true;

// Forward declarations
void handle_power_failure(void);
void handle_timer(void);
void handle_keyboard(void);
void handle_printer(void);
void handle_disk(void);

// Device array (daisy chain representation)
Device devices[MAX_DEVICES];

// Initialize daisy chain with priority ordering
void init_daisy_chain(void) {
 // Create devices in priority order (highest first)
 devices[0] = (Device){0, PRIORITY_POWER_FAILURE, "PowerFail", true, handle_power_failure, NULL};
 devices[1] = (Device){1, PRIORITY_TIMER, "Timer", true, handle_timer, &devices[0]};
 devices[2] = (Device){2, PRIORITY_KEYBOARD, "Keyboard", true, handle_keyboard, &devices[1]};
 devices[3] = (Device){3, PRIORITY_PRINTER, "Printer", true, handle_printer, &devices[2]};
 devices[4] = (Device){4, PRIORITY_DISK, "Disk", true, handle_disk, &devices[3]};

 printf("[System] Daisy chain initialized (highest priority at end)\n");
}

// Generate interrupt from a device
void generate_interrupt(int device_id) {
 printf("[Device] %s raising interrupt\n", devices[device_id].name);

 switch(device_id) {
 case 0: irq_register.power_fail = 1; break;
 case 1: irq_register.timer = 1; break;
 case 2: irq_register.keyboard = 1; break;
 case 3: irq_register.printer = 1; break;
 case 4: irq_register.disk = 1; break;
 }
}

// Check and service interrupts based on priority
void check_and_service_interrupts(void) {
 if (!global_interrupt_enable) {
 return;
 }

 // Disable interrupts during service
 global_interrupt_enable = false;

 // Scan daisy chain from highest to lowest priority
 // (in our array, highest priority is at index 0)
 for (int i = 0; i < MAX_DEVICES; i++) {
 bool interrupt_pending = false;

 switch(i) {
 case 0: interrupt_pending = irq_register.power_fail; break;
 case 1: interrupt_pending = irq_register.timer; break;
 case 2: interrupt_pending = irq_register.keyboard; break;
 case 3: interrupt_pending = irq_register.printer; break;
 case 4: interrupt_pending = irq_register.disk; break;
 }

 if (interrupt_pending && devices[i].interrupt_enabled) {
 printf("[Interrupt] Servicing %s (Priority: %d)\n", 
 devices[i].name, devices[i].priority);

 // Call device's ISR
 devices[i].handler();

 // Clear interrupt request
 switch(i) {
 case 0: irq_register.power_fail = 0; break;
 case 1: irq_register.timer = 0; break;
 case 2: irq_register.keyboard = 0; break;
 case 3: irq_register.printer = 0; break;
 case 4: irq_register.disk = 0; break;
 }

 // Higher priority interrupt being serviced blocks lower ones
 break; 
 }
 }

 // Re-enable interrupts
 global_interrupt_enable = true;
}

// Interrupt Service Routines
void handle_power_failure(void) {
 printf("[ISR] EMERGENCY: Saving system state to battery backup\n");
}

void handle_timer(void) {
 printf("[ISR] Timer tick: Updating system clock\n");
}

void handle_keyboard(void) {
 printf("[ISR] Keyboard: Reading key press\n");
}

void handle_printer(void) {
 printf("[ISR] Printer: Buffer ready for more data\n");
}

void handle_disk(void) {
 printf("[ISR] Disk: Data transfer complete\n");
}

int main(void) {
 printf("\n=== Interrupt Priority Daisy Chain Demo ===\n\n");

 // Initialize the daisy chain
 init_daisy_chain();

 printf("\n--- Scenario 1: Multiple simultaneous interrupts ---\n");
 generate_interrupt(3); // Printer (low priority)
 generate_interrupt(1); // Timer (high priority)
 check_and_service_interrupts();

 printf("\n--- Scenario 2: Power failure during normal operation ---\n");
 generate_interrupt(2); // Keyboard
 generate_interrupt(0); // Power failure (highest)
 check_and_service_interrupts();

 printf("\n--- Scenario 3: Disk interrupt ---\n");
 generate_interrupt(4); // Disk
 check_and_service_interrupts();

 printf("\n=== Demo Complete ===\n");
 return 0;
}
